import Foundation
import Combine

// MARK: - Recording State

enum RecordingState: Equatable {
    case idle
    case recording(startedAt: Date)
    case processing

    var isRecording: Bool {
        if case .recording = self { return true }
        return false
    }

    var duration: TimeInterval? {
        guard case .recording(let start) = self else { return nil }
        return Date().timeIntervalSince(start)
    }
}

// MARK: - Transcription Entry

struct TranscriptionEntry: Identifiable, Equatable {
    let id = UUID()
    let text: String
    let timestamp: Date
    let duration: TimeInterval // audio segment duration in seconds

    var formattedTimestamp: String {
        let f = DateFormatter()
        f.timeStyle = .medium
        f.dateStyle = .none
        return f.string(from: timestamp)
    }
}

// MARK: - App State (Task 2.3)

@MainActor
final class AppState: ObservableObject {
    // Recording
    @Published var recordingState: RecordingState = .idle
    @Published var audioLevel: Float = 0.0          // 0.0 - 1.0 for waveform
    @Published var bufferWarning: Bool = false       // ring buffer overflow warning

    // Transcription
    @Published var entries: [TranscriptionEntry] = []
    @Published var isModelLoaded: Bool = false
    @Published var modelLoadError: String? = nil

    // Errors
    @Published var micPermissionDenied: Bool = false
    @Published var accessibilityPermissionGranted: Bool = false

    // Preferences
    @Published var selectedModel: WhisperModel {
        didSet { UserDefaults.standard.set(selectedModel.rawValue, forKey: "selectedModel") }
    }
    @Published var vadSilenceThresholdMs: Int = 500

    // E2E 测试钩子：由 AppDelegate 注入，供 SwiftUI 按钮调用
    var toggleRecordingAction: (() -> Void)?
    // 偏好设置入口：由 AppDelegate 注入，StatusBarManager 和 TranscriptionPopoverView 统一调用
    var openPreferencesAction: (() -> Void)?

    init() {
        let stored = UserDefaults.standard.string(forKey: "selectedModel")
        selectedModel = stored.flatMap(WhisperModel.init(rawValue:)) ?? .tiny
    }

    // MARK: Computed

    var allTranscriptionText: String {
        entries.map(\.text).joined(separator: "\n")
    }

    var recordingDuration: TimeInterval {
        recordingState.duration ?? 0
    }

    // MARK: Mutations

    func appendEntry(_ entry: TranscriptionEntry) {
        entries.append(entry)
    }

    func clearSession() {
        entries.removeAll()
    }

    func startRecording() {
        recordingState = .recording(startedAt: Date())
    }

    func stopRecording() {
        recordingState = .idle
        audioLevel = 0
    }
}

// MARK: - Whisper Model

enum WhisperModel: String, CaseIterable, Identifiable {
    case tiny             = "ggml-tiny"
    case base             = "ggml-base"
    case small            = "ggml-small"
    case medium           = "ggml-medium"
    case largeV2          = "ggml-large-v2"
    case largeV3          = "ggml-large-v3"
    case largeV3Q5_0      = "ggml-large-v3-q5_0"
    case largeV3TurboQ5_0 = "ggml-large-v3-turbo-q5_0"

    var id: String { rawValue }

    var displayName: String {
        switch self {
        case .tiny:             return "Tiny (~75 MB)"
        case .base:             return "Base (~142 MB)"
        case .small:            return "Small (~244 MB)"
        case .medium:           return "Medium (~769 MB)"
        case .largeV2:          return "Large v2 (~2.87 GB)"
        case .largeV3:          return "Large v3 (~2.87 GB)"
        case .largeV3Q5_0:      return "Large v3 Q5_0 (~1.1 GB)"
        case .largeV3TurboQ5_0: return "Large v3 Turbo Q5_0 (~0.6 GB)"
        }
    }

    /// 量化模型标记，在 UI 中显示"推荐"标签
    var isRecommended: Bool {
        switch self {
        case .largeV3Q5_0, .largeV3TurboQ5_0: return true
        default: return false
        }
    }

    var filename: String { "\(rawValue).bin" }

    /// Hugging Face / ggerganov CDN download URL
    var downloadURL: URL {
        URL(string: "https://huggingface.co/ggerganov/whisper.cpp/resolve/main/\(filename)")!
    }
}

import AppKit
import SwiftUI
import Combine
import KeyboardShortcuts

// MARK: - KeyboardShortcuts Name (Task 3.1)

extension KeyboardShortcuts.Name {
    static let toggleRecording = Self("toggleRecording", default: .init(.space, modifiers: .option))
}

// MARK: - App Delegate (Task 2.1)

@MainActor
final class AppDelegate: NSObject, NSApplicationDelegate {

    // Core services (Task 2.4 - DI via AppDelegate ownership)
    let appState = AppState()
    /// 提升到顶层，供 VoicePepperApp Scene 在 applicationDidFinishLaunching 前安全访问
    let modelManager = WhisperModelManager()
    private var statusBarManager: StatusBarManager?
    private var audioCaptureService: AudioCaptureService?
    private var transcriptionService: TranscriptionService?
    private var accessibilityMonitor: AccessibilityMonitor?

    private var cancellables = Set<AnyCancellable>()
    /// 手动管理偏好设置窗口，避免 .accessory app 中 showSettingsWindow: 不可靠的问题
    private var preferencesWindow: NSWindow?

    // MARK: Lifecycle

    func applicationWillFinishLaunching(_ notification: Notification) {
        terminatePreviousInstances()
    }

    func applicationDidFinishLaunching(_ notification: Notification) {
        // Configure as agent (LSUIElement=YES in Info.plist handles dock hiding)
        NSApp.setActivationPolicy(.accessory)

        // Wire services
        setupServices()
        setupStatusBar()
        setupHotkey()
        setupAccessibilityMonitor()
        setupBindings()
    }

    func applicationWillTerminate(_ notification: Notification) {
        audioCaptureService?.stop()
        transcriptionService?.stop()
        // ggml-metal 析构链在 exit() 路径上会触发 GGML_ASSERT 并卡入 UE 状态；
        // _exit() 跳过 C++ 析构，由内核直接回收所有 GPU/文件资源，安全可靠。
        _exit(0)
    }

    // MARK: Single Instance

    /// 终止同名旧实例，确保同一时刻只有一个 VoicePepper 运行。
    /// 策略：先发 SIGTERM 优雅退出，2 秒后若仍存在则 SIGKILL 强杀。
    private func terminatePreviousInstances() {
        let myPID = ProcessInfo.processInfo.processIdentifier
        let myName = ProcessInfo.processInfo.processName

        let stale = NSWorkspace.shared.runningApplications.filter {
            $0.processIdentifier != myPID && $0.localizedName == myName
        }

        guard !stale.isEmpty else { return }

        for app in stale {
            let pid = app.processIdentifier
            NSLog("[AppDelegate] 终止旧实例 PID=\(pid)")
            // 直接 SIGKILL：跳过 ggml-metal 析构路径，避免旧实例卡入 UE 状态
            kill(pid, SIGKILL)
        }

        // 等待 OS 回收旧实例资源（status bar 槽位、Metal 上下文等）
        Thread.sleep(forTimeInterval: 1.0)
    }

    // MARK: Setup

    private func setupServices() {
        let audioService = AudioCaptureService(appState: appState)
        let transcriptionSvc = TranscriptionService(appState: appState, modelManager: modelManager)

        audioCaptureService = audioService
        transcriptionService = transcriptionSvc

        // Start model loading immediately on launch
        transcriptionSvc.start()

        // E2E 测试钩子：允许 SwiftUI 按钮通过 AppState 触发录音
        appState.toggleRecordingAction = { [weak self] in
            self?.handleToggleRecording()
        }

        // 偏好设置入口：手动创建 NSWindow，规避 .accessory app 中 showSettingsWindow: 不可靠
        appState.openPreferencesAction = { [weak self] in
            self?.openPreferencesWindow()
        }

        // Connect audio → transcription
        audioService.audioSegmentPublisher
            .sink { [weak transcriptionSvc] segment in
                transcriptionSvc?.enqueue(segment)
            }
            .store(in: &cancellables)
    }

    private func setupStatusBar() {
        statusBarManager = StatusBarManager(appState: appState)
    }

    private func setupHotkey() {
        // Task 3.1 - register ⌥Space via KeyboardShortcuts
        KeyboardShortcuts.onKeyUp(for: .toggleRecording) { [weak self] in
            Task { @MainActor in
                self?.handleToggleRecording()
            }
        }
    }

    private func setupAccessibilityMonitor() {
        // Task 3.3 - poll for accessibility permission changes
        accessibilityMonitor = AccessibilityMonitor { [weak self] granted in
            Task { @MainActor in
                self?.appState.accessibilityPermissionGranted = granted
            }
        }
        accessibilityMonitor?.start()

        // Update initial state
        appState.accessibilityPermissionGranted = AXIsProcessTrusted()
    }

    private func setupBindings() {
        // Keep model load state in sync (TranscriptionService loads async)
        transcriptionService?.modelReadyPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] ready in
                self?.appState.isModelLoaded = ready
            }
            .store(in: &cancellables)

        transcriptionService?.modelErrorPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] error in
                self?.appState.modelLoadError = error
            }
            .store(in: &cancellables)
    }

    // MARK: Recording Control

    func handleToggleRecording() {
        NSLog("[AppDelegate] handleToggleRecording called, AXTrusted=%d, isRecording=%d",
              AXIsProcessTrusted() ? 1 : 0,
              appState.recordingState.isRecording ? 1 : 0)
        // Task 3.2 - check accessibility permission before recording
        guard AXIsProcessTrusted() else {
            NSLog("[AppDelegate] 未获得辅助功能权限，显示提示")
            promptAccessibilityPermission()
            return
        }

        if appState.recordingState.isRecording {
            stopRecording()
        } else {
            startRecording()
        }
    }

    private func startRecording() {
        audioCaptureService?.start { [weak self] error in
            Task { @MainActor in
                if let error {
                    self?.appState.micPermissionDenied = (error == .permissionDenied)
                } else {
                    self?.appState.startRecording()
                }
            }
        }
    }

    private func stopRecording() {
        audioCaptureService?.stop()
        appState.stopRecording()
    }

    // MARK: Preferences Window

    func openPreferencesWindow() {
        // 若窗口已存在且可见，直接置前
        if let window = preferencesWindow, window.isVisible {
            window.makeKeyAndOrderFront(nil)
            NSApp.activate(ignoringOtherApps: true)
            return
        }

        let view = PreferencesView()
            .environmentObject(appState)
            .environmentObject(modelManager)

        let vc = NSHostingController(rootView: view)
        let window = NSWindow(contentViewController: vc)
        window.title = "偏好设置"
        window.styleMask = [.titled, .closable, .miniaturizable]
        window.setContentSize(NSSize(width: 420, height: 520))
        window.center()
        window.makeKeyAndOrderFront(nil)
        NSApp.activate(ignoringOtherApps: true)

        preferencesWindow = window
    }

    // MARK: Permission Prompts

    private func promptAccessibilityPermission() {
        let options: NSDictionary = [kAXTrustedCheckOptionPrompt.takeRetainedValue(): true]
        AXIsProcessTrustedWithOptions(options)
    }
}

import AVFoundation
import Combine

// MARK: - Audio Capture Error

enum AudioCaptureError: Error, Equatable {
    case permissionDenied
    case engineStartFailed(String)
    case converterSetupFailed
}

// MARK: - Audio Segment

/// A segment of 16kHz mono PCM audio ready for transcription
struct AudioSegment {
    let samples: [Float]        // 16kHz mono float32
    let capturedAt: Date
}

// MARK: - Audio Capture Service (Tasks 4.1 - 4.6)

final class AudioCaptureService {

    /// Emits completed audio segments (post-VAD silence detection)
    let audioSegmentPublisher = PassthroughSubject<AudioSegment, Never>()
    /// Emits current RMS level 0..1 for waveform display
    let levelPublisher = PassthroughSubject<Float, Never>()

    private let engine = AVAudioEngine()
    private var converter: AVAudioConverter?
    private let ringBuffer = AudioRingBuffer()           // 30min capacity
    private let vadDetector = VADDetector()

    private weak var appState: AppState?
    private var cancellables = Set<AnyCancellable>()

    // Whisper requires 16kHz mono
    private let targetFormat = AVAudioFormat(
        commonFormat: .pcmFormatFloat32,
        sampleRate: 16000,
        channels: 1,
        interleaved: false
    )!

    init(appState: AppState) {
        self.appState = appState

        // Propagate overflow warning to AppState (Task 4.5)
        ringBuffer.overflowPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak appState] in
                Task { @MainActor in
                    appState?.bufferWarning = true
                }
            }
            .store(in: &cancellables)

        // Hook VAD segment-complete → publish AudioSegment
        vadDetector.onSegmentComplete = { [weak self] samples in
            guard let self else { return }
            let segment = AudioSegment(samples: samples, capturedAt: Date())
            self.audioSegmentPublisher.send(segment)
        }
    }

    // MARK: - Start / Stop

    func start(completion: @escaping (AudioCaptureError?) -> Void) {
        // Task 4.6 - check/request microphone permission
        AVCaptureDevice.requestAccess(for: .audio) { [weak self] granted in
            if granted {
                DispatchQueue.main.async {
                    do {
                        try self?.startEngine()
                        completion(nil)
                    } catch let err as AudioCaptureError {
                        completion(err)
                    } catch {
                        completion(.engineStartFailed(error.localizedDescription))
                    }
                }
            } else {
                DispatchQueue.main.async {
                    completion(.permissionDenied)
                }
            }
        }
    }

    func stop() {
        engine.inputNode.removeTap(onBus: 0)
        engine.stop()

        // Flush remaining samples as final segment
        let remaining = ringBuffer.drainAll()
        if !remaining.isEmpty {
            audioSegmentPublisher.send(AudioSegment(samples: remaining, capturedAt: Date()))
        }

        vadDetector.reset()
        ringBuffer.reset()

        DispatchQueue.main.async { [weak self] in
            self?.appState?.audioLevel = 0
        }
    }

    // MARK: - Engine Setup

    private func startEngine() throws {
        let inputNode = engine.inputNode
        let inputFormat = inputNode.outputFormat(forBus: 0)

        // Setup converter: input → 16kHz mono float32 (Task 4.3)
        guard let conv = AVAudioConverter(from: inputFormat, to: targetFormat) else {
            throw AudioCaptureError.converterSetupFailed
        }
        self.converter = conv

        // Task 4.2 - install tap with 1024 frame buffer
        inputNode.installTap(onBus: 0, bufferSize: 1024, format: inputFormat) { [weak self] buffer, _ in
            self?.processTapBuffer(buffer)
        }

        engine.prepare()
        do {
            try engine.start()
        } catch {
            throw AudioCaptureError.engineStartFailed(error.localizedDescription)
        }
    }

    // MARK: - Buffer Processing

    private func processTapBuffer(_ inputBuffer: AVAudioPCMBuffer) {
        guard let converter,
              let outputBuffer = AVAudioPCMBuffer(
                pcmFormat: targetFormat,
                frameCapacity: AVAudioFrameCount(
                    Double(inputBuffer.frameLength) * targetFormat.sampleRate / inputBuffer.format.sampleRate + 1
                )
              ) else { return }

        var error: NSError?
        var inputConsumed = false

        // Task 4.3 - convert to 16kHz mono
        converter.convert(to: outputBuffer, error: &error) { _, outStatus in
            if inputConsumed {
                outStatus.pointee = .noDataNow
                return nil
            }
            outStatus.pointee = .haveData
            inputConsumed = true
            return inputBuffer
        }

        guard error == nil, outputBuffer.frameLength > 0,
              let channelData = outputBuffer.floatChannelData else { return }

        let samples = Array(UnsafeBufferPointer(
            start: channelData[0],
            count: Int(outputBuffer.frameLength)
        ))

        // Compute RMS for waveform display
        let rms = computeRMS(samples)
        DispatchQueue.main.async { [weak self] in
            self?.appState?.audioLevel = rms
        }

        // Feed into VAD detector
        vadDetector.feed(samples: samples)
    }

    // MARK: - Helpers

    private func computeRMS(_ samples: [Float]) -> Float {
        guard !samples.isEmpty else { return 0 }
        let sumSq = samples.reduce(0) { $0 + $1 * $1 }
        return min(1.0, sqrt(sumSq / Float(samples.count)) * 10)
    }
}

import SwiftUI
import AppKit

// MARK: - Transcription Popover View (Task 6.2)
// Main panel: status bar at top, transcript list, action buttons at bottom.

struct TranscriptionPopoverView: View {
    @EnvironmentObject var appState: AppState

    @State private var showClearConfirm = false
    @State private var showCopiedFeedback = false

    var body: some View {
        VStack(spacing: 0) {

            // Top: Recording status bar (timer + waveform) - Task 6.4
            RecordingStatusBar()
                .environmentObject(appState)
                .accessibilityElement(children: .contain)
                .accessibilityIdentifier("recordingStatusBar")

            Divider()

            // Middle: Transcript list (scrollable) - Task 6.3
            TranscriptionListView()
                .environmentObject(appState)
                .frame(minHeight: 300)

            Divider()

            // Bottom: Action bar
            actionBar
        }
        .frame(width: 400, height: 460)
        .background(Color(NSColor.windowBackgroundColor))
        // .contain 保留子元素各自的 accessibilityIdentifier，避免 SwiftUI 平铺时被父 id 覆盖
        .accessibilityElement(children: .contain)
        .accessibilityIdentifier("transcriptionPopover")
        // E2E 测试钩子：零尺寸隐藏按钮，通过 AX 触发录音切换
        .overlay(alignment: .topLeading) {
            Button("") {
                NSLog("[TestButton] testToggleRecordingButton pressed")
                appState.toggleRecordingAction?()
            }
            .frame(width: 1, height: 1)
            .opacity(0.01)
            .accessibilityLabel("Toggle Recording")
            .accessibilityIdentifier("testToggleRecordingButton")
        }
    }

    // MARK: Action Bar

    private var actionBar: some View {
        HStack {
            // 偏好设置入口
            Button {
                appState.openPreferencesAction?()
            } label: {
                Image(systemName: "gearshape")
                    .font(.caption)
            }
            .buttonStyle(.borderless)
            .help("偏好设置 (模型选择、快捷键…)")
            .accessibilityIdentifier("settingsButton")

            // Clear session (Task 6.7)
            Button(role: .destructive) {
                showClearConfirm = true
            } label: {
                Label("清除", systemImage: "trash")
                    .font(.caption)
            }
            .buttonStyle(.borderless)
            .disabled(appState.entries.isEmpty)
            .accessibilityIdentifier("clearButton")
            .confirmationDialog(
                "清除所有转录内容？",
                isPresented: $showClearConfirm,
                titleVisibility: .visible
            ) {
                Button("清除", role: .destructive) {
                    appState.clearSession()
                }
                Button("取消", role: .cancel) {}
            }

            Spacer()

            // Entry count
            if !appState.entries.isEmpty {
                Text("\(appState.entries.count) 条")
                    .font(.caption2)
                    .foregroundColor(.secondary)
            }

            // Copy all (Task 6.6)
            Button {
                copyAll()
            } label: {
                Label(showCopiedFeedback ? "已复制" : "复制全部", systemImage: "doc.on.doc")
                    .font(.caption)
            }
            .buttonStyle(.bordered)
            .disabled(appState.entries.isEmpty)
            .accessibilityIdentifier("copyAllButton")
        }
        .padding(.horizontal, 16)
        .padding(.vertical, 8)
    }

    // MARK: Copy Action (Task 6.6)

    private func copyAll() {
        NSPasteboard.general.clearContents()
        NSPasteboard.general.setString(appState.allTranscriptionText, forType: .string)

        // 200ms feedback
        withAnimation {
            showCopiedFeedback = true
        }
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.2) {
            withAnimation {
                showCopiedFeedback = false
            }
        }
    }
}

