}

// MARK: - Recording File Service

/// 负责将录音会话 PCM 样本持久化为 M4A 文件，并管理历史录音列表。
/// 所有方法均为 @MainActor 以避免并发冲突；写盘操作内部使用 detached Task 异步执行。
@MainActor
final class RecordingFileService: ObservableObject {

    // MARK: 存储目录

    /// ~/Library/Application Support/VoicePepper/Recordings/
    var storageDirectory: URL {
        let appSupport = FileManager.default.urls(for: .applicationSupportDirectory, in: .userDomainMask).first!
        let dir = appSupport.appendingPathComponent("VoicePepper/Recordings", isDirectory: true)
        if !FileManager.default.fileExists(atPath: dir.path) {
            try? FileManager.default.createDirectory(at: dir, withIntermediateDirectories: true)
        }
        return dir
    }

    // MARK: 列表

    /// 按录制时间降序排列的历史录音
    @Published private(set) var recordings: [RecordingItem] = []

    func loadRecordings() {
        let dir = storageDirectory
        do {
            let urls = try FileManager.default.contentsOfDirectory(
                at: dir,
                includingPropertiesForKeys: [.contentModificationDateKey, .fileSizeKey],
                options: .skipsHiddenFiles
            )
            let m4aURLs = urls.filter { $0.pathExtension.lowercased() == "m4a" }

            recordings = m4aURLs.compactMap { url -> RecordingItem? in
                let attrs = try? url.resourceValues(forKeys: [.contentModificationDateKey])
                let createdAt = attrs?.contentModificationDate ?? Date()
                let duration = Self.durationOf(url: url)
                return RecordingItem(id: UUID(), url: url, duration: duration, createdAt: createdAt)
            }
            .sorted { $0.createdAt > $1.createdAt }

        } catch {
            NSLog("[RecordingFileService] 无法枚举录音目录: %@", error.localizedDescription)
        }
    }

    // MARK: 保存

    /// 将整个会话的完整 PCM 样本异步写为一个 M4A 文件。
    /// - Parameters:
    ///   - samples: 16kHz mono Float32 样本（所有 VAD 段合并后）
    ///   - sampleRate: 采样率（默认 16000）
    func save(samples: [Float], sampleRate: Double = 16000) {
        guard !samples.isEmpty else { return }
        let outputURL = makeOutputURL()
        Task.detached(priority: .utility) { [weak self] in
            do {
                try await Self.writeM4A(samples: samples, sampleRate: sampleRate, to: outputURL)
                let duration = Double(samples.count) / sampleRate
                let item = RecordingItem(id: UUID(), url: outputURL, duration: duration, createdAt: Date())
                await MainActor.run {
                    self?.recordings.insert(item, at: 0)
                }
                NSLog("[RecordingFileService] 已保存: %@", outputURL.lastPathComponent)
            } catch {
                NSLog("[RecordingFileService] 写盘失败: %@", error.localizedDescription)
            }
        }
    }

    // MARK: 删除

    func delete(item: RecordingItem) {
        do {
            try FileManager.default.removeItem(at: item.url)
        } catch {
            NSLog("[RecordingFileService] 删除失败: %@", error.localizedDescription)
        }
        recordings.removeAll { $0.id == item.id }
    }

    // MARK: 私有工具

    private func makeOutputURL() -> URL {
        let formatter = DateFormatter()
        formatter.dateFormat = "yyyyMMdd_HHmmss"
        let name = "Recording_\(formatter.string(from: Date())).m4a"
        return storageDirectory.appendingPathComponent(name)
    }

    private static func durationOf(url: URL) -> TimeInterval {
        let asset = AVURLAsset(url: url)
        let duration = asset.duration
        guard duration.timescale > 0 else { return 0 }
        return CMTimeGetSeconds(duration)
    }

    // MARK: AVAssetWriter 写盘

    private static func writeM4A(samples: [Float], sampleRate: Double, to outputURL: URL) async throws {
        let writer = try AVAssetWriter(outputURL: outputURL, fileType: .m4a)

        let settings: [String: Any] = [
            AVFormatIDKey: kAudioFormatMPEG4AAC,
            AVSampleRateKey: sampleRate,
            AVNumberOfChannelsKey: 1,
            AVEncoderBitRateKey: 96_000
        ]
        let input = AVAssetWriterInput(mediaType: .audio, outputSettings: settings)
        input.expectsMediaDataInRealTime = false
        writer.add(input)

        let sourceFormat = AVAudioFormat(
            commonFormat: .pcmFormatFloat32,
            sampleRate: sampleRate,
            channels: 1,
            interleaved: false
        )!

        guard let formatDesc = sourceFormat.formatDescription else {
            throw NSError(domain: "RecordingFileService", code: -1,
                          userInfo: [NSLocalizedDescriptionKey: "无法创建音频格式描述"])
        }

        let adaptor = AVAssetWriterInputAudioMixerBehavior.self
        _ = adaptor  // suppress unused warning

        writer.startWriting()
        writer.startSession(atSourceTime: .zero)

        // 分块写入（每块 4096 样本）以避免单次 CMBlockBuffer 过大
        let chunkSize = 4096
        var offset = 0
        var sampleTime: CMTime = .zero
        let sampleDuration = CMTime(value: CMTimeValue(chunkSize), timescale: CMTimeScale(sampleRate))

        while offset < samples.count {
            guard input.isReadyForMoreMediaData else {
                await Task.yield()
                continue
            }

            let end = min(offset + chunkSize, samples.count)
            let chunk = Array(samples[offset..<end])
            let frameCount = chunk.count

            var blockBuffer: CMBlockBuffer?
            let blockSize = frameCount * MemoryLayout<Float>.size

            var status = CMBlockBufferCreateWithMemoryBlock(
                allocator: kCFAllocatorDefault,
                memoryBlock: nil,
                blockLength: blockSize,
                blockAllocator: nil,
                customBlockSource: nil,
                offsetToData: 0,
                dataLength: blockSize,
                flags: 0,
                blockBufferOut: &blockBuffer
            )
            guard status == noErr, let bb = blockBuffer else { break }

            status = CMBlockBufferFillDataBytes(
                with: 0,
                blockBuffer: bb,
                offsetIntoDestination: 0,
                dataLength: blockSize
            )
            guard status == noErr else { break }

            chunk.withUnsafeBytes { ptr in
                CMBlockBufferReplaceDataBytes(
                    with: ptr.baseAddress!,
                    blockBuffer: bb,
                    offsetIntoDestination: 0,
                    dataLength: blockSize
                )
            }

            var sampleBuffer: CMSampleBuffer?
            var timingInfo = CMSampleTimingInfo(
                duration: sampleDuration,
                presentationTimeStamp: sampleTime,
                decodeTimeStamp: .invalid
            )
            var frameCountVar = frameCount

            status = CMSampleBufferCreate(
                allocator: kCFAllocatorDefault,
                dataBuffer: bb,
                dataReady: true,
                makeDataReadyCallback: nil,
                refcon: nil,
                formatDescription: formatDesc,
                sampleCount: frameCount,
                sampleTimingEntryCount: 1,
                sampleTimingArray: &timingInfo,
                sampleSizeEntryCount: 1,
                sampleSizeArray: &frameCountVar,
                sampleBufferOut: &sampleBuffer
            )

            if status == noErr, let sb = sampleBuffer {
                input.append(sb)
            }

            sampleTime = CMTimeAdd(sampleTime, CMTime(value: CMTimeValue(frameCount),
                                                      timescale: CMTimeScale(sampleRate)))
            offset = end
        }

        input.markAsFinished()

        await withCheckedContinuation { (continuation: CheckedContinuation<Void, Never>) in
            writer.finishWriting {
                continuation.resume()
            }
        }

        if writer.status == .failed {
            throw writer.error ?? NSError(domain: "RecordingFileService", code: -2,
                                          userInfo: [NSLocalizedDescriptionKey: "AVAssetWriter 写入失败"])
        }
    }
}

