        do {
            let urls = try FileManager.default.contentsOfDirectory(
                at: dir,
                includingPropertiesForKeys: [.contentModificationDateKey],
                options: .skipsHiddenFiles
            )
            recordings = urls
                // 同时支持 wav（新格式）和旧的空 m4a 文件（排除零字节文件）
                .filter {
                    let ext = $0.pathExtension.lowercased()
                    guard ext == "wav" || ext == "m4a" else { return false }
                    let size = (try? FileManager.default.attributesOfItem(atPath: $0.path)[.size] as? Int) ?? 0
                    return size > 0
                }
                .compactMap { url -> RecordingItem? in
                    let attrs = try? url.resourceValues(forKeys: [.contentModificationDateKey])
                    let createdAt = attrs?.contentModificationDate ?? Date()
                    let duration = Self.durationOf(url: url)
                    return RecordingItem(id: UUID(), url: url, duration: duration, createdAt: createdAt)
                }
                .sorted { $0.createdAt > $1.createdAt }
        } catch {
            NSLog("[RecordingFileService] 无法枚举录音目录: %@", error.localizedDescription)
        }
    }

    // MARK: 保存

    /// 将整个会话的完整 PCM 样本异步写为一个 WAV 文件（合并所有 VAD 段）。
    func save(samples: [Float], sampleRate: Double = 16000) {
        guard !samples.isEmpty else { return }
        let outputURL = makeOutputURL()
        Task { @MainActor [weak self] in
            guard let self else { return }
            do {
                let duration = try await Task.detached(priority: .utility) {
                    try Self.writeWAV(samples: samples, sampleRate: sampleRate, to: outputURL)
                }.value
                let item = RecordingItem(id: UUID(), url: outputURL, duration: duration, createdAt: Date())
                self.recordings.insert(item, at: 0)
                NSLog("[RecordingFileService] 已保存: %@ (%.1fs)", outputURL.lastPathComponent, duration)
            } catch {
                NSLog("[RecordingFileService] 写盘失败: %@", error.localizedDescription)
            }
        }
    }

    // MARK: 删除

    func delete(item: RecordingItem) {
        do {
            try FileManager.default.removeItem(at: item.url)
        } catch {
            NSLog("[RecordingFileService] 删除失败: %@", error.localizedDescription)
        }
        recordings.removeAll { $0.id == item.id }
    }

    // MARK: 私有工具

    private func makeOutputURL() -> URL {
        let formatter = DateFormatter()
        formatter.dateFormat = "yyyyMMdd_HHmmss"
        let name = "Recording_\(formatter.string(from: Date())).wav"
        return storageDirectory.appendingPathComponent(name)
    }

    private static func durationOf(url: URL) -> TimeInterval {
        guard let audioFile = try? AVAudioFile(forReading: url) else { return 0 }
        let sampleRate = audioFile.processingFormat.sampleRate
        guard sampleRate > 0 else { return 0 }
        return Double(audioFile.length) / sampleRate
    }

    // MARK: 写盘（nonisolated，在后台线程调用）

    /// 将 Float32 PCM 样本写入 WAV 文件，返回实际时长（秒）。
    /// WAV 格式直写，无需 AAC 编码，兼容所有 macOS 版本。
    private nonisolated static func writeWAV(samples: [Float], sampleRate: Double, to outputURL: URL) throws -> TimeInterval {
        let wavSettings: [String: Any] = [
            AVFormatIDKey: kAudioFormatLinearPCM,
            AVSampleRateKey: sampleRate,
            AVNumberOfChannelsKey: 1,
            AVLinearPCMBitDepthKey: 32,
            AVLinearPCMIsFloatKey: true,
            AVLinearPCMIsBigEndianKey: false,
            AVLinearPCMIsNonInterleaved: false
        ]

        let pcmFormat = AVAudioFormat(
            commonFormat: .pcmFormatFloat32,
            sampleRate: sampleRate,
            channels: 1,
            interleaved: false
        )!

        let audioFile = try AVAudioFile(forWriting: outputURL, settings: wavSettings)

        let chunkSize = 65_536
        var offset = 0

        while offset < samples.count {
            let end = min(offset + chunkSize, samples.count)
            let chunkCount = end - offset

            guard let buffer = AVAudioPCMBuffer(
                pcmFormat: pcmFormat,
                frameCapacity: AVAudioFrameCount(chunkCount)
            ) else { break }

            buffer.frameLength = AVAudioFrameCount(chunkCount)
            if let channelData = buffer.floatChannelData {
                samples.withUnsafeBufferPointer { ptr in
                    channelData[0].update(from: ptr.baseAddress! + offset, count: chunkCount)
                }
            }

            try audioFile.write(from: buffer)
            offset = end
        }

        return Double(samples.count) / sampleRate
    }
}

import AppKit
import SwiftUI
import Combine

// MARK: - Status Bar Manager (Task 2.2)

@MainActor
final class StatusBarManager {

    private var statusItem: NSStatusItem
    private var popover: NSPopover
    private var appState: AppState
    private var cancellables = Set<AnyCancellable>()

    // Pulse animation timer for recording state
    private var pulseTimer: Timer?
    private var pulsePhase: Bool = false

    init(appState: AppState) {
        self.appState = appState
        self.statusItem = NSStatusBar.system.statusItem(withLength: NSStatusItem.squareLength)
        self.popover = NSPopover()

        configurePopover()
        configureStatusItem()
        observeState()
    }

    // MARK: Configuration

    private func configurePopover() {
        let popoverView = TranscriptionPopoverView()
            .environmentObject(appState)

        let contentVC = NSHostingController(rootView: popoverView)
        contentVC.view.frame = NSRect(x: 0, y: 0, width: 400, height: 500)

        popover.contentViewController = contentVC
        popover.behavior = .transient
        popover.animates = true
    }

    private func configureStatusItem() {
        guard let button = statusItem.button else { return }
        button.image = NSImage(systemSymbolName: "mic", accessibilityDescription: "VoicePepper")
        button.imagePosition = .imageOnly
        button.action = #selector(handleClick)
        button.sendAction(on: [.leftMouseUp, .rightMouseUp])
        button.target = self
        button.setAccessibilityIdentifier("statusBarMicButton")

        updateIcon(isRecording: false)
    }

    // MARK: Click Handling

    @objc private func handleClick() {
        guard let event = NSApp.currentEvent else { return }
        if event.type == .rightMouseUp {
            showContextMenu()
        } else {
            togglePopover()
        }
    }

    private func showContextMenu() {
        let menu = NSMenu()

        let prefsItem = NSMenuItem(title: "偏好设置…", action: #selector(openPreferences), keyEquivalent: ",")
        prefsItem.target = self
        menu.addItem(prefsItem)

        menu.addItem(.separator())

        // target = NSApp：直接发给 NSApplication，避免因 target=self 导致按钮 gray out
        let quitItem = NSMenuItem(title: "退出 VoicePepper", action: #selector(NSApplication.terminate(_:)), keyEquivalent: "q")
        quitItem.target = NSApp
        menu.addItem(quitItem)

        statusItem.menu = menu
        statusItem.button?.performClick(nil)
        // 用后清除，保持左键单击正常
        DispatchQueue.main.async { [weak self] in self?.statusItem.menu = nil }
    }

    @objc private func openPreferences() {
        appState.openPreferencesAction?()
    }

    private func observeState() {
        appState.$recordingState
            .receive(on: DispatchQueue.main)
            .sink { [weak self] state in
                self?.updateIcon(isRecording: state.isRecording)
            }
            .store(in: &cancellables)
    }

    // MARK: Icon Update (Task 6.1 - pulse animation)

    private func updateIcon(isRecording: Bool) {
        guard let button = statusItem.button else { return }

        if isRecording {
            // Start pulse animation
            pulseTimer?.invalidate()
            pulseTimer = Timer.scheduledTimer(withTimeInterval: 0.6, repeats: true) { [weak self, weak button] _ in
                Task { @MainActor [weak self, weak button] in
                    guard let self, let button else { return }
                    self.pulsePhase.toggle()
                    let symbolName = self.pulsePhase ? "mic.fill" : "mic"
                    button.image = NSImage(systemSymbolName: symbolName, accessibilityDescription: "Recording")
                    button.contentTintColor = .systemRed
                }
            }
        } else {
            pulseTimer?.invalidate()
            pulseTimer = nil
            pulsePhase = false
            button.image = NSImage(systemSymbolName: "mic", accessibilityDescription: "VoicePepper")
            button.contentTintColor = nil
        }
    }

    // MARK: Popover Toggle

    // MARK: Popover Toggle

    @objc private func togglePopover() {
        if popover.isShown {
            popover.performClose(nil)
        } else {
            guard let button = statusItem.button else { return }
            popover.show(relativeTo: button.bounds, of: button, preferredEdge: .minY)
            popover.contentViewController?.view.window?.makeKey()
        }
    }
}

import AVFoundation
import Combine

// MARK: - Audio Capture Error

enum AudioCaptureError: Error, Equatable {
    case permissionDenied
    case engineStartFailed(String)
    case converterSetupFailed
}

// MARK: - Audio Segment

/// A segment of 16kHz mono PCM audio ready for transcription
struct AudioSegment {
    let samples: [Float]        // 16kHz mono float32
    let capturedAt: Date
}

// MARK: - Audio Capture Service (Tasks 4.1 - 4.6)

final class AudioCaptureService {

    /// Emits completed audio segments (post-VAD silence detection)
    let audioSegmentPublisher = PassthroughSubject<AudioSegment, Never>()
    /// Emits current RMS level 0..1 for waveform display
    let levelPublisher = PassthroughSubject<Float, Never>()
    /// 录音会话结束时发出，携带本次会话全部 PCM 样本（所有 VAD 段合并）
    let sessionEndPublisher = PassthroughSubject<[Float], Never>()

    /// 当前录音会话累积的 PCM 样本（所有 VAD 段依次追加）
    private var sessionSamples: [Float] = []

    private let engine = AVAudioEngine()
    private var converter: AVAudioConverter?
    private let ringBuffer = AudioRingBuffer()           // 30min capacity
    private let vadDetector = VADDetector()

    private weak var appState: AppState?
    private var cancellables = Set<AnyCancellable>()

    // Whisper requires 16kHz mono
    private let targetFormat = AVAudioFormat(
        commonFormat: .pcmFormatFloat32,
        sampleRate: 16000,
        channels: 1,
        interleaved: false
    )!

    init(appState: AppState) {
        self.appState = appState

        // Propagate overflow warning to AppState (Task 4.5)
        ringBuffer.overflowPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak appState] in
                Task { @MainActor in
                    appState?.bufferWarning = true
                }
            }
            .store(in: &cancellables)

        // Hook VAD segment-complete → publish AudioSegment + 累积会话样本
        vadDetector.onSegmentComplete = { [weak self] samples in
            guard let self else { return }
            let segment = AudioSegment(samples: samples, capturedAt: Date())
            self.audioSegmentPublisher.send(segment)
            self.sessionSamples.append(contentsOf: samples)
        }
    }

    // MARK: - Start / Stop

    func start(completion: @escaping (AudioCaptureError?) -> Void) {
        // Task 4.6 - check/request microphone permission
        AVCaptureDevice.requestAccess(for: .audio) { [weak self] granted in
            if granted {
                DispatchQueue.main.async {
                    do {
                        try self?.startEngine()
                        completion(nil)
                    } catch let err as AudioCaptureError {
                        completion(err)
                    } catch {
                        completion(.engineStartFailed(error.localizedDescription))
                    }
                }
            } else {
                DispatchQueue.main.async {
                    completion(.permissionDenied)
                }
            }
        }
    }

    func stop() {
        engine.inputNode.removeTap(onBus: 0)
        engine.stop()

        // Flush remaining samples as final segment
        let remaining = ringBuffer.drainAll()
        if !remaining.isEmpty {
            let segment = AudioSegment(samples: remaining, capturedAt: Date())
            audioSegmentPublisher.send(segment)
            sessionSamples.append(contentsOf: remaining)
        }

        // 发出完整会话样本供持久化，然后清空缓冲
        let completedSession = sessionSamples
        if !completedSession.isEmpty {
            sessionEndPublisher.send(completedSession)
        }
        sessionSamples.removeAll()

        vadDetector.reset()
        ringBuffer.reset()

        DispatchQueue.main.async { [weak self] in
            self?.appState?.audioLevel = 0
        }
    }

    // MARK: - Engine Setup

    private func startEngine() throws {
        let inputNode = engine.inputNode
        let inputFormat = inputNode.outputFormat(forBus: 0)

        // Setup converter: input → 16kHz mono float32 (Task 4.3)
        guard let conv = AVAudioConverter(from: inputFormat, to: targetFormat) else {
            throw AudioCaptureError.converterSetupFailed
        }
        self.converter = conv

        // Task 4.2 - install tap with 1024 frame buffer
        inputNode.installTap(onBus: 0, bufferSize: 1024, format: inputFormat) { [weak self] buffer, _ in
            self?.processTapBuffer(buffer)
        }

        engine.prepare()
        do {
            try engine.start()
        } catch {
            throw AudioCaptureError.engineStartFailed(error.localizedDescription)
        }
    }

    // MARK: - Buffer Processing

    private func processTapBuffer(_ inputBuffer: AVAudioPCMBuffer) {
        guard let converter,
              let outputBuffer = AVAudioPCMBuffer(
                pcmFormat: targetFormat,
                frameCapacity: AVAudioFrameCount(
                    Double(inputBuffer.frameLength) * targetFormat.sampleRate / inputBuffer.format.sampleRate + 1
                )
              ) else { return }

        var error: NSError?
        var inputConsumed = false

        // Task 4.3 - convert to 16kHz mono
        converter.convert(to: outputBuffer, error: &error) { _, outStatus in
            if inputConsumed {
                outStatus.pointee = .noDataNow
                return nil
            }
            outStatus.pointee = .haveData
            inputConsumed = true
            return inputBuffer
        }

        guard error == nil, outputBuffer.frameLength > 0,
              let channelData = outputBuffer.floatChannelData else { return }

        let samples = Array(UnsafeBufferPointer(
            start: channelData[0],
            count: Int(outputBuffer.frameLength)
        ))

        // Compute RMS for waveform display
        let rms = computeRMS(samples)
        DispatchQueue.main.async { [weak self] in
            self?.appState?.audioLevel = rms
        }

        // Feed into VAD detector
        vadDetector.feed(samples: samples)
    }

    // MARK: - Helpers

    private func computeRMS(_ samples: [Float]) -> Float {
        guard !samples.isEmpty else { return 0 }
        let sumSq = samples.reduce(0) { $0 + $1 * $1 }
        return min(1.0, sqrt(sumSq / Float(samples.count)) * 10)
    }
}

import Foundation
import Combine

// MARK: - Recording State

enum RecordingState: Equatable {
    case idle
    case recording(startedAt: Date)
    case processing

    var isRecording: Bool {
        if case .recording = self { return true }
        return false
    }

    var duration: TimeInterval? {
        guard case .recording(let start) = self else { return nil }
        return Date().timeIntervalSince(start)
    }
}

// MARK: - Transcription Entry

struct TranscriptionEntry: Identifiable, Equatable {
    let id = UUID()
    let text: String
    let timestamp: Date
    let duration: TimeInterval // audio segment duration in seconds

    var formattedTimestamp: String {
        let f = DateFormatter()
        f.timeStyle = .medium
        f.dateStyle = .none
        return f.string(from: timestamp)
    }
}

// MARK: - App State (Task 2.3)

@MainActor
final class AppState: ObservableObject {
    // Recording
    @Published var recordingState: RecordingState = .idle
    @Published var audioLevel: Float = 0.0          // 0.0 - 1.0 for waveform
    @Published var bufferWarning: Bool = false       // ring buffer overflow warning

    // Transcription
    @Published var entries: [TranscriptionEntry] = []
    @Published var isModelLoaded: Bool = false
    @Published var modelLoadError: String? = nil

    // Errors
    @Published var micPermissionDenied: Bool = false
    @Published var accessibilityPermissionGranted: Bool = false

    // 历史录音（由 RecordingFileService 驱动）
    var recordingFileService: RecordingFileService?
    /// 当前正在播放的录音 ID（nil 表示无播放）
    @Published var currentlyPlayingId: UUID? = nil

    // Preferences
    @Published var selectedModel: WhisperModel {
        didSet { UserDefaults.standard.set(selectedModel.rawValue, forKey: "selectedModel") }
    }
    @Published var vadSilenceThresholdMs: Int = 500

    // E2E 测试钩子：由 AppDelegate 注入，供 SwiftUI 按钮调用
    var toggleRecordingAction: (() -> Void)?
    // 偏好设置入口：由 AppDelegate 注入，StatusBarManager 和 TranscriptionPopoverView 统一调用
    var openPreferencesAction: (() -> Void)?

    init() {
        let stored = UserDefaults.standard.string(forKey: "selectedModel")
        selectedModel = stored.flatMap(WhisperModel.init(rawValue:)) ?? .tiny
    }

    // MARK: Computed

    var allTranscriptionText: String {
        entries.map(\.text).joined(separator: "\n")
    }

    var recordingDuration: TimeInterval {
        recordingState.duration ?? 0
    }

    // MARK: Mutations

    func appendEntry(_ entry: TranscriptionEntry) {
        entries.append(entry)
    }

    func clearSession() {
        entries.removeAll()
    }

    func startRecording() {
        recordingState = .recording(startedAt: Date())
    }

    func stopRecording() {
        recordingState = .idle
        audioLevel = 0
    }
}

// MARK: - Whisper Model

enum WhisperModel: String, CaseIterable, Identifiable {
    case tiny             = "ggml-tiny"
    case base             = "ggml-base"
    case small            = "ggml-small"
    case medium           = "ggml-medium"
    case largeV2          = "ggml-large-v2"
    case largeV3          = "ggml-large-v3"
    case largeV3Q5_0      = "ggml-large-v3-q5_0"
    case largeV3TurboQ5_0 = "ggml-large-v3-turbo-q5_0"

    var id: String { rawValue }

    var displayName: String {
        switch self {
        case .tiny:             return "Tiny (~75 MB)"
        case .base:             return "Base (~142 MB)"
        case .small:            return "Small (~244 MB)"
        case .medium:           return "Medium (~769 MB)"
        case .largeV2:          return "Large v2 (~2.87 GB)"
        case .largeV3:          return "Large v3 (~2.87 GB)"
        case .largeV3Q5_0:      return "Large v3 Q5_0 (~1.1 GB)"
        case .largeV3TurboQ5_0: return "Large v3 Turbo Q5_0 (~0.6 GB)"
        }
    }

    /// 量化模型标记，在 UI 中显示"推荐"标签
    var isRecommended: Bool {
        switch self {
        case .largeV3Q5_0, .largeV3TurboQ5_0: return true
        default: return false
        }
    }

    var filename: String { "\(rawValue).bin" }

    /// Hugging Face / ggerganov CDN download URL
    var downloadURL: URL {
        URL(string: "https://huggingface.co/ggerganov/whisper.cpp/resolve/main/\(filename)")!
    }
}

